import{_ as p,o as a,c as e,j as r,a as t,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"都市之魂","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/通用及综合类/都市之魂.md","filePath":"4.资源分区/6.技艺及称号/通用及综合类/都市之魂.md"}'),n={name:"4.资源分区/6.技艺及称号/通用及综合类/都市之魂.md"};function o(d,b,l,_,i,c){return a(),e("div",null,[...b[0]||(b[0]=[r("h1",{id:"都市之魂",tabindex:"-1"},[t("都市之魂 "),r("a",{class:"header-anchor",href:"#都市之魂","aria-label":'Permalink to "都市之魂"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"灵魂蓝调015")])])],-1),s('<h1 id="都市之魂-1" tabindex="-1">都市之魂 <a class="header-anchor" href="#都市之魂-1" aria-label="Permalink to &quot;都市之魂&quot;">​</a></h1><p>都市之魂</p><p>“街道即我血脉，建筑即我骨骼。扰我城镇，即我寇仇。”——Parethian, urban soul of Rel Astra</p><p>都市之魂是被城市之神选中的斗士，负责从各种或明或暗的威胁——掠食的怪物，犯罪及其他的不稳定因素——之中保护城市居民。</p><p>前提：技能：学识上专业（城市规划）1级<br> 都市之魂的职业特性专注于在城市和大社区中生存。你的许多能力都需要你处在城市的边界内才能使用。为了决定你的职业特性，这里“城市”这个名词指的是任何有多于5000人的聚落（因此，至少像小城市一样大）。</p><p>D级：D+500</p><p>职业能力：城市壁垒 城市支持 聆听城市</p><p>城市壁垒：每天一次，持续一个场景；当处于城市内，你可以自由动作呼唤聚落集体意识的帮助来强化你的身体和意识。在城市壁垒状态下，你获得2点三豁免上的增强加值和一点DR1/-</p><p>城市支持：你依赖城市的存在来满足你的身体需求，而当你在这些区域外旅行的时候你不得不忍受一些痛苦。<br> 在城市内的时候，人物的自然恢复伤势所需时间减半。但代价是，当你在城市外时，你的自然恢复降低到0，不能进行任何自然回复（即使你之后购买了自然恢复翻倍的能力也无法恢复，因为0翻倍依然是0）</p><p>城市连结：这个职业特性在你的城市你给你提供了巨大的力量，但是作为交换，限制了你旅行的灵活性。只有你在城市的边界当中，你不会变老（如果你离开城镇，你正常变老），这是C级的【免疫衰老】的效果，同时只要你在城市内，便获得足以维持一种较为奢华生活所需的货币，如可以入住昂贵的酒店，到平均消费较高的餐厅就餐，外出打车，天天抽中华，支付该城市允许的医疗和娱乐服务消费，但因此获得的货币无法用来投资、雇佣安保、贿赂或购资产，具体由st决定。如果你所处城市的人口跌落到5,000以下，你失去你的城市连结特性直到人口重新恢复</p><p>B级：B+2000<br> 特殊的，购买本称号不会获得自由属性点</p><p>职业能力：融入城市 城市察觉</p><p>融入城市：当你处于城市边界内时，你可以将你的身体和所有物融入建筑墙体、街道，或者任何城市的石质，土质建筑成分内，且在这些成分内移动时，你的速度获得10加成。</p><p>聆听城市：当你处于城市内时，可以和建筑、街道或者城市的其他非生命体部分对话，这些物品会以自己的感官，告诉你这里曾经发生的事情，例如城市内的摄像头（如果有的话）可以直接告诉你它看到的，而马路雕像之类不具有光学器官的建筑，则只能告诉你他在某一时刻的感受，你最多只能获取一天内发生事件的有关信息。人物每支付1点意志，便可延长该对话一分钟，具体的内容由ST决定,这是一个B级时空来源的能力。</p><p>B级：B+2000</p><p>职业能力：觉晓城市 城市守护</p><p>觉晓城市<br> 每当你进入一座城市。你都会立刻得到城市周边相关的知识，像是自己成为城市本身一样。你能立刻得知下列讯息的其中三项：该城市的人口、此城市的优势种族与该种族所占的比例、特定种族的人口比例、权力中心的类型与阵营（若权力中心有一个以上则ST随机选定一个告诉pl）、对该城市经济贸易最重要的影响因素或是城内最强大的物品，这是B级命运来源的效果</p><p>城市守护<br> 城市主动护卫你避免你受到伤害，保护你的可能会是墙壁、街灯柱或是其它构成物。　<br> 你在面对所有的攻击与法术时都能视为得到大量掩护，获得5点遮蔽防御，并且因为你和城市的亲和性，城市会对你起到如同护甲在身一般的防御效果，额外获得5点护甲防御。在你进行攻击行动的在同一时间，城市会重新组成以配合你的行动，当你进行攻击或施放法术时，而你的敌人无法从墙壁、物体或其它城市的构成物得到掩蔽（全掩蔽除外）。　<br> =========================================================================<br> 技能树，都市之魂下属技能树分类为神术，信仰指向城市之神【乌班纳斯】，该技能树下的施法检定均为智力+学识+专业：城市规划作为检定构成，正常获得其他资源提供的施法加成</p><p>城市定位术<br> 阵营：秩序<br> 价格：1000<br> 等级：无支线<br> 动作：自由动作<br> 持续：无<br> 射程：无<br> 目标：见描述<br> 对抗：无<br> 施展此法术时，你能感知距离你最近一个城市的方位与距离，并能决定搜寻的生物聚集地至少要达到什么样的规模，举例来说，你可以探寻距离你最近且规模至少为乡村的居群，或仅寻找距离你最近的城市。</p><p>此法术测定的是离目标城市「最近」的距离，在旅途中可能必需寻找其它的道路以避开那些固体障碍，因此，此术的施放者十分讨厌在自己身处地表的时探测到脚下距离他半里的地下城市，而地表上离他最近的城市却不到5里。</p><p>跃步楼顶<br> 阵营：秩序<br> 价格：500<br> 等级：无支线<br> 动作：移动+迅捷动作<br> 持续：一轮<br> 射程：自身<br> 目标：见描述<br> 对抗：无<br> 让你能轻易在不平坦的表面上行走。<br> 释放后，你能轻松的在屋顶或是类似的不规则表面跳跃前进，你每次跳跃的最大距离等同于你的移动速度，高度则为你移动速度的一半，这种跳跃无需进行检定。</p><p>城楼之光<br> 阵营：秩序<br> 价格：C+1000<br> 等级：C<br> 动作：标准动作<br> 持续：一轮<br> 射程：65米<br> 目标：见描述<br> 对抗：强韧豁免<br> 前提：见描述<br> 你吸收周边所有的人工光线，将其转换为闪耀的火光。任何人工光线（普通自然的光线）将暂时熄灭，随后从你身上炸裂出闪耀的焰花。　<br> 效果：在施法后，你无法造成伤害，但你前方180度施法范围内的所有生物（除了你以外，包括友方）都将受到等同于伤害数的目眩点数，使用强韧豁免对抗。在这之后所有光线都会回复正常，此法术对不依靠视觉的生物无效。</p><p>要施展此法术，施法者身边60米必需有3个以上的人工光线（火把、提灯、路灯，霓虹或其它类似的东西）。此法术因其最常被使用的区域（明亮的街道上）而得名，但只要有足够的光源，就能在任何地方施展。</p><p>城市漫步<br> 阵营：秩序<br> 价格：C+1000<br> 等级：C<br> 动作：标准动作<br> 持续：无<br> 射程：无<br> 目标：见描述<br> 对抗：无<br> 城市漫步：你可以随意通过魔法在城市之间旅行，从一个城市的公交站，码头或者其他类似的设施，开始施法传送引导，然后选择在同一个位面的一个特定城镇的市郊到达。<br> 你不能指定一个特定的终点，这个能力将你送到一个由ST决定的正好在城市边上的安全地点（如果有的话），如果这个指明的城市不存在或者城市边上没有安全地点，这个能力失败。<br> 在该次传送中，你能携带不超过你负重能力的物品及自愿生物，与你共同传送。<br> 为了启动这个能力，你必须专注足够长的时间，你与目的地城市的距离决定了你需要专注多长时间，当然，你并不会在能力启动前因专注时间过长而需要进食或休息。如果你的专注被打断，你必须重新开始。<br> 传送距离与专注时间关系大致如下：<br> 500km 10分钟<br> 1000km 30分钟<br> 此后，距离每增加500km，则时间再额外增加30分钟<br> 这是C级时空来源的传送效果</p><p>迷绕径巷<br> 阵营：秩序<br> 价格：C+1000<br> 等级：C<br> 动作：标准动作<br> 持续：一场景<br> 射程：40米<br> 目标：见描述<br> 对抗：意志豁免<br> 前提：处于城市内<br> 受术者感觉城里的墙壁开始朝他四周靠拢。</p><p>效果：选择一个目标作为受术者进行一次施法检定，受术者使用意志豁免进行对抗，若受术者对抗失败，他就会相信自己被困在由狭窄的城市小巷所构成，不断歪曲旋转的迷宫里，在他的认知里，其敏感范围内可被所有的目标，无论敌友，都会变成某种可怖的，伺机伤害他的东西，若他要攻击，则只能不分敌友的随机选定一人攻击，且优先攻击那些距离自己更近，危害更大的生物，这是一个C级心灵来源的支配效果。同时，因为场景的变化，原本他所熟悉的道路已经不在，他也无法快速逃离这里，他在远离该场景的任何人时，其速度都只有一半，这并非时他本身速度的降低，而是在不停的折返转圈重浪费了时间，这是一个C级心灵来源的思维暗示效果。</p><p>活化城市<br> 阵营：秩序<br> 等级：B<br> 价格：B+2000<br> 动作：标准动作<br> 持续：一轮<br> 射程：20米<br> 目标：见描述<br> 对抗：反射豁免<br> 前提：处于城市内<br> 建筑物与其它构成城市的事物开始攻击你的敌人。</p><p>效果：进行一次施法检定，所有待在法术范围内的敌人将受到一次来自巨型活化物体发动的近战攻击，被攻击目标需要以反射豁免，受到差值的伤害。此外，所有被命中的敌人的地面速度归0。伤害活化城市的构成体不会对法术造成任何影响，这是一个B级环境来源的变身效果</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',30)])])}const m=p(n,[["render",o]]);export{f as __pageData,m as default};
